import React, { useState, useRef, useEffect } from 'react';

export default function TextareaCounter({ maxLength = 200 }) {
  const [text, setText] = useState("");
  const textareaRef = useRef(null);

  const length = text.length;
  const isNearLimit = length >= maxLength * 0.9;
  const isOverLimit = length > maxLength;

  // Auto-resize height handler
  useEffect(() => {
    if (textareaRef.current) {
      textareaRef.current.style.height = "auto";
      textareaRef.current.style.height = `${textareaRef.current.scrollHeight}px`;
    }
  }, [text]);

  const handleChange = (e) => {
    setText(e.target.value);
  };

  return (
    <div className="w-full max-w-md">
      <textarea
        ref={textareaRef}
        rows={3}
        value={text}
        onChange={handleChange}
        className={`w-full p-4 border-2 rounded-xl text-sm text-gray-700 bg-white outline-none resize-none transition focus:ring-2 ${
          isOverLimit
            ? 'border-red-400 focus:ring-red-200 focus:border-red-400'
            : isNearLimit
            ? 'border-yellow-400 focus:ring-yellow-200 focus:border-yellow-400'
            : 'border-gray-200 focus:ring-purple-200 focus:border-purple-500'
        }`}
        placeholder="Type something..."
      />
      <div className="flex justify-end mt-1.5">
        <span className={`text-xs font-semibold ${
          isOverLimit ? 'text-red-500' : isNearLimit ? 'text-yellow-500' : 'text-gray-400'
        }`}>
          {length} / {maxLength}
        </span>
      </div>
    </div>
  );
}
